#!/usr/bin/env bash
# Resolve benchmarks/results.md merge conflicts automatically (POSIX/Linux/macOS
# counterpart of resolve-benchmark-conflicts.ps1).
#
# benchmarks/results.md is regenerated by CI on every push to master, so it
# should never need a manual merge. The repo's .gitattributes maps it to
# `merge=ours`, but that only works once the 'ours' driver is registered in this
# clone — which this script does. After running once, plain `git pull`
# auto-resolves results.md forever; you never have to run this again.
#
# Usage: scripts/resolve-benchmark-conflicts.sh [origin/master]
set -uo pipefail

REMOTE_BRANCH="${1:-origin/master}"
RESULTS="benchmarks/results.md"

GIT_DIR="$(git rev-parse --git-dir 2>/dev/null)" || { echo "Not a git repository."; exit 1; }

echo "Tauraro Benchmark Conflict Resolver"
echo "==================================="
echo ""

# 1. Register the merge driver referenced by .gitattributes (idempotent). `true`
#    keeps the current branch's version of the file and exits 0, so a 3-way merge
#    of results.md never reports a conflict.
git config merge.ours.driver true
echo "Merge driver registered — results.md conflicts now auto-resolve on every pull."
echo ""

unmerged()        { git diff --name-only --diff-filter=U 2>/dev/null; }
other_conflicts() { unmerged | grep -v -F -x "$RESULTS" || true; }

# Keep OUR results.md and stage it; succeed only if no OTHER files conflict.
resolve_results_only() {
    if unmerged | grep -qx -F "$RESULTS"; then
        echo "Resolving $RESULTS (keeping your version)..."
        git checkout --ours -- "$RESULTS" 2>/dev/null || true
        git add "$RESULTS" 2>/dev/null || true
    fi
    [ -z "$(other_conflicts)" ]
}

show_other() { echo "Conflicts remain in files other than $RESULTS:"; other_conflicts | sed 's/^/    /'; }

# 2a. Finish an in-progress MERGE.
if [ -f "$GIT_DIR/MERGE_HEAD" ]; then
    echo "A merge is in progress — completing it..."
    if resolve_results_only; then
        git commit --no-edit; echo "Merge completed."
    else
        show_other; echo "Resolve those, then run: git commit --no-edit"; exit 1
    fi
    exit 0
fi

# 2b. Finish an in-progress REBASE.
if [ -d "$GIT_DIR/rebase-merge" ] || [ -d "$GIT_DIR/rebase-apply" ]; then
    echo "A rebase is in progress — continuing it..."
    if resolve_results_only; then
        git rebase --continue; echo "Rebase continued."
    else
        show_other; echo "Resolve those, then run: git rebase --continue"; exit 1
    fi
    exit 0
fi

# 3. Clean start: stash local edits, pull (results.md auto-resolves), restore.
STASHED=false
if [ -n "$(git status --porcelain)" ]; then
    echo "Stashing your local changes..."
    git stash push -u -m "resolve-benchmark-conflicts auto-stash" >/dev/null && STASHED=true
fi

REMOTE="${REMOTE_BRANCH%%/*}"
echo "Fetching $REMOTE..."
git fetch "$REMOTE" >/dev/null 2>&1 || true

echo "Merging $REMOTE_BRANCH (results.md auto-resolves to yours)..."
if ! git merge --no-edit "$REMOTE_BRANCH"; then
    if resolve_results_only; then
        git commit --no-edit; echo "Merged; results.md kept yours."
    else
        show_other
        [ "$STASHED" = true ] && echo "Your changes are stashed — after resolving, run: git stash pop"
        exit 1
    fi
fi

if [ "$STASHED" = true ]; then
    echo "Restoring your stashed changes..."
    git stash pop
fi

echo ""
echo "Done. Push with: git push $REMOTE $(git rev-parse --abbrev-ref HEAD)"
